#include <string.h>

static inline int em_check_rtps_magic(const char *payload) {
    if (payload == NULL) return 0;

    // RTPS magic bytes: 'R' 'T' 'P' 'S' (0x52 0x54 0x50 0x53)
    if ((unsigned char)payload[0] == 0x52 &&
        (unsigned char)payload[1] == 0x54 &&
        (unsigned char)payload[2] == 0x50 &&
        (unsigned char)payload[3] == 0x53) {
        return 1;
    }
    return 0;
}

static inline int em_is_dds_port(double port) {
    int p = (int)port;
    // Standard DDS/RTPS discovery and data port range: 7400-7415
    if (p >= 7400 && p <= 7415) return 1;
    return 0;
}
